mapper.sql:
WHERE p.is_deleted = false

    AND (LOWER(p.title) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
         OR LOWER(p.content) LIKE LOWER(CONCAT('%', #{keyword}, '%')))


    AND p.category = #{category}


    AND p.status = #{status}

